import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void oneStep() {
        // n=1: only one way — take a single step
        assertEquals(1, new Solution().climbStairs(1));
    }

    @Test
    void twoSteps() {
        // n=2: [1,1] or [2] → 2 ways
        assertEquals(2, new Solution().climbStairs(2));
    }

    @Test
    void fourSteps() {
        // n=4: 5 ways — Fibonacci(5)
        assertEquals(5, new Solution().climbStairs(4));
    }

    @Test
    void fiveSteps() {
        // n=5: 8 ways — Fibonacci(6)
        assertEquals(8, new Solution().climbStairs(5));
    }

    @Test
    void tenSteps() {
        // n=10: Fibonacci(11) = 89
        assertEquals(89, new Solution().climbStairs(10));
    }

    @Test
    void maxConstraint() {
        // n=45: answer fits in int (1,836,311,903)
        assertEquals(1836311903, new Solution().climbStairs(45));
    }
}
